mapper.sql:
SELECT EL.APPLY_NO, TO_CHAR(EL.APPLY_TIME, 'DD-MM-YYYY') AS APPLY_TIME, EL.PERSON_ID, AR_GET_DAY_HOURS(EL.PERSON_ID, TO_CHAR(EL.LEAVE_FROM_TIME, 'YYYY/MM/DD')) AS DAY_HOURS, TO_CHAR(EL.LEAVE_FROM_TIME, 'DD-MM-YYYY HH24:MI') AS LEAVE_FROM_TIME, TO_CHAR(EL.LEAVE_TO_TIME, 'DD-MM-YYYY HH24:MI') AS LEAVE_TO_TIME, TRUNC(EL.LEAVE_TO_TIME - SYSDATE) AS OVER_DAY, TRUNC(((EL.LEAVE_TO_TIME - SYSDATE) - TRUNC(EL.LEAVE_TO_TIME - SYSDATE)) * 24) AS OVER_HOUR, EL.LEAVE_REASON, EL.LEAVE_TYPE_CODE, GET_GLOBAL_NAME(EL.LEAVE_TYPE_CODE, #{lang, jdbcType=VARCHAR}) AS LEAVE_TYPE_CODE_NAME, EL.HR_COMMENT, EL.APPLY_LENGTH, EL.CONFIRM_FLAG, EL.ACTIVITY, EL.CREATED_BY, GET_UPDATED_INFO(EL.CREATED_BY) AS CREATED_NAME, HR.LOCAL_NAME, HR.DEPTNO, HR.EMPID, GET_DEPT_NAME(HR.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, HR.POST_GRADE_NO, GET_GLOBAL_NAME(HR.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POST_GRADE_NAME, HR.POST_FAMILY, GET_GLOBAL_NAME(HR.POST_FAMILY, #{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, GET_UPDATED_INFO(EL.CONFIRM_BY) AS CONFIRM_BY FROM ESS_LEAVE_APPLY_TB EL JOIN HR_EMPLOYEE HR ON EL.PERSON_ID = HR.PERSON_ID WHERE EL.AFFIRM_FLAG = 14014308 AND EL.PERSON_ID NOT LIKE '111111%' AND EL.ACTIVITY = '1' AND EL.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND EL.CONFIRM_FLAG = #{searchConfirmFlag, jdbcType=VARCHAR}
AND (UPPER(HR.EMPID) LIKE '%' || UPPER(#{searchEmpId, jdbcType=VARCHAR}) || '%' OR CONVERTTOUNSIGN(UPPER(HR.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchEmpId, jdbcType=VARCHAR})) || '%')
AND CONVERTTOUNSIGN(UPPER(HR.LOCAL_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{searchLocalName, jdbcType=VARCHAR})) || '%'
AND EL.LEAVE_TYPE_CODE = #{searchLeaveTypeCode, jdbcType=VARCHAR}
AND EL.LEAVE_FROM_TIME >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND EL.LEAVE_FROM_TIME < TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD') + 1

mapper.select:
SELECT * FROM (
    SELECT INNER_Q.*, ROWNUM AS RN FROM (

        ORDER BY EL.APPLY_TIME DESC
    ) INNER_Q
    WHERE ROWNUM <= #{start, jdbcType=INTEGER} + #{length, jdbcType=INTEGER}
) WHERE RN > #{start, jdbcType=INTEGER}

